--
-- Name: app_is_assistant_member(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.app_is_assistant_member(p_assistant_id uuid, p_user_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM assistant_members
     WHERE assistant_id = p_assistant_id
       AND user_id = p_user_id
  );
$$;


--
-- Name: contacts_company_workspace_match(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.contacts_company_workspace_match() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.company_id IS NOT NULL THEN
    IF (SELECT workspace_id FROM companies WHERE id = NEW.company_id) <> NEW.workspace_id THEN
      RAISE EXCEPTION 'company_id must reference a company in the same workspace';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: deals_links_workspace_match(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.deals_links_workspace_match() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.contact_id IS NOT NULL THEN
    IF (SELECT workspace_id FROM contacts WHERE id = NEW.contact_id) <> NEW.workspace_id THEN
      RAISE EXCEPTION 'contact_id must reference a contact in the same workspace';
    END IF;
  END IF;
  IF NEW.company_id IS NOT NULL THEN
    IF (SELECT workspace_id FROM companies WHERE id = NEW.company_id) <> NEW.workspace_id THEN
      RAISE EXCEPTION 'company_id must reference a company in the same workspace';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: ke_search_vector_update(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ke_search_vector_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.search_vector :=
    setweight(to_tsvector('english', COALESCE(NEW.title, '')), 'A') ||
    setweight(to_tsvector('english', COALESCE(NEW.summary, '')), 'B') ||
    setweight(to_tsvector('english', COALESCE(array_to_string(NEW.tags, ' '), '')), 'B') ||
    setweight(to_tsvector('english', COALESCE(NEW.content, '')), 'C');
  RETURN NEW;
END;
$$;


--
-- Name: sensitivity_rank(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sensitivity_rank(s text) RETURNS integer
    LANGUAGE sql IMMUTABLE STRICT
    AS $$
    SELECT CASE s
      WHEN 'public'       THEN 1
      WHEN 'internal'     THEN 2
      WHEN 'confidential' THEN 3
    END
$$;


