);


--
-- Name: COLUMN memories.original_scope; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.memories.original_scope IS 'Scope as initially saved by the model. Set on INSERT only when the writer is a model; never updated. Used to compute user-correction deltas.';


--
-- Name: COLUMN memories.original_sensitivity; Type: COMMENT; Schema: public; Owner: -
--

