--
-- Name: COLUMN memories.original_summary; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.memories.original_summary IS 'Summary as initially saved by the model. Set on INSERT only when the writer is a model; never updated. Used to compute user-correction deltas.';


