);


--
-- Name: TABLE memory_recall_events; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.memory_recall_events IS 'Per-turn log of which memories informed which assistant responses. Joins downstream with feedback to surface bad-outcome memories.';


--
-- Name: COLUMN memory_recall_events.assistant_message_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.memory_recall_events.assistant_message_id IS 'The session_messages row this recall informed (assistant turn). Nullable because recall happens before the message commits; the chat route''s per-turn buffer attaches the id at flush time.';


--
-- Name: COLUMN memory_recall_events.recall_kind; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.memory_recall_events.recall_kind IS 'tool_call: model explicitly called getMemory. index_inject: memory landed in the per-turn memory index. consolidation: read during a background consolidation phase (REM / Deep).';


