    total_saves_30d integer DEFAULT 0 NOT NULL,
    total_verifications_30d integer DEFAULT 0 NOT NULL,
    scope_narrow_rate numeric(4,3),
    scope_wide_rate numeric(4,3),
    sensitivity_over_rate numeric(4,3),
    sensitivity_under_rate numeric(4,3),
    prompt_snippet text,
    prompt_snippet_version integer DEFAULT 0 NOT NULL,
    last_refreshed_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT now() NOT NULL
);


--
-- Name: TABLE workspace_memory_evolution; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.workspace_memory_evolution IS 'Per-workspace aggregated user-correction patterns; emits a Layer 2 prompt snippet that biases future model behavior in this workspace.';


--
-- Name: COLUMN workspace_memory_evolution.scope_narrow_rate; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workspace_memory_evolution.scope_narrow_rate IS 'Fraction of recent verifications where the user widened the model''s scope (e.g. personal → workspace_shared). High value ⇒ model is too narrow.';


--
-- Name: COLUMN workspace_memory_evolution.scope_wide_rate; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workspace_memory_evolution.scope_wide_rate IS 'Fraction of recent verifications where the user narrowed the model''s scope (e.g. workspace_shared → personal). High value ⇒ model is too wide.';


--
-- Name: COLUMN workspace_memory_evolution.sensitivity_over_rate; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workspace_memory_evolution.sensitivity_over_rate IS 'Fraction of recent verifications where the user lowered the model''s sensitivity (confidential → internal). High value ⇒ model over-classifies.';


--
-- Name: COLUMN workspace_memory_evolution.sensitivity_under_rate; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workspace_memory_evolution.sensitivity_under_rate IS 'Fraction of recent verifications where the user raised the model''s sensitivity (internal → confidential). High value ⇒ model under-classifies.';


--
-- Name: COLUMN workspace_memory_evolution.prompt_snippet; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.workspace_memory_evolution.prompt_snippet IS 'Layer 2 injection text built by the worker from the rates above. NULL when no rate crossed the significance threshold (15%).';


